+
+    it('should return updated frequency', () => {
+      service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });
+      expect(service.getEmailFrequency('user-1')).toBe('daily-digest');
+    });
+  });
+
+  describe('deletePreferences', () => {
+    it('should return false for non-existent preferences', () => {
+      expect(service.deletePreferences('user-1')).toBe(false);
