/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently focused on email (the only active channel);
 * designed to extend to additional channels later.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': sent as events occur
 * - 'daily-digest': batched into a daily summary
 * - 'weekly-digest': batched into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency. */
  frequency: EmailFrequency;
  /** Notification types the user wants to receive via email. */
  subscribedCategories: NotificationType[];
}

/**
 * Per-user notification preferences.
 */
export interface UserPreferences {
  userId: string;
  email: EmailPreferences;
  updatedAt: Date;
}

/**
 * Input for creating or fully replacing a user's preferences.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification types — used as the default subscription set.
 */
export const ALL_NOTIFICATION_TYPES: NotificationType[] = [
  'order:confirmation',
  'order:status-update',
  'user:welcome',
  'user:profile-updated',
];

/**
 * Returns default preferences for a new user (all notifications enabled).
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  return {
    userId,
    email: {
      enabled: true,
      frequency: 'immediate',
      subscribedCategories: [...ALL_NOTIFICATION_TYPES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages per-user notification preferences.
 *
 * Stores preferences in memory. Users who have never set preferences
 * get defaults (all email notifications enabled, immediate delivery).
 *
 * Used by NotificationService to check whether a notification should
 * be sent to a given user on a given channel.
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import { createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Get preferences for a user. Returns defaults if none have been set.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return { ...existing, email: { ...existing.email, subscribedCategories: [...existing.email.subscribedCategories] } };
    }
    return createDefaultPreferences(userId);
  }

  /**
   * Update a user's email notification preferences.
   * Only provided fields are changed; others keep their current values.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    const updated: UserPreferences = {
      userId,
      email: {
        enabled: input.enabled ?? current.email.enabled,
        frequency: input.frequency ?? current.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...current.email.subscribedCategories],
      },
      updatedAt: new Date(),
    };

    this.preferences.set(userId, updated);
    this.logger.info(`Updated email preferences for user ${userId}`);
    return this.getPreferences(userId);
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if:
   *   1. Email is enabled for the user
   *   2. The notification type is in the user's subscribed categories
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);
    if (!prefs.email.enabled) {
      this.logger.info(`Email disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }
    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType}, skipping`);
      return false;
    }
    return true;
  }

  /**
   * Get the email frequency setting for a user.
   */
  getEmailFrequency(userId: string): UserPreferences['email']['frequency'] {
    return this.getPreferences(userId).email.frequency;
  }

  /**
   * Delete preferences for a user (reverts to defaults).
   */
  deletePreferences(userId: string): boolean {
    const existed = this.preferences.has(userId);
    this.preferences.delete(userId);
    if (existed) {
      this.logger.info(`Deleted preferences for user ${userId}`);
    }
    return existed;
  }

  /**
   * Clear all stored preferences. Useful for testing.
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

