import { describe, it, expect, beforeEach } from 'vitest';
import { PreferencesService } from '../../src/services/preferences.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { ALL_NOTIFICATION_TYPES, createDefaultPreferences } from '../../src/models/user-preferences.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let service: PreferencesService;

  beforeEach(() => {
    service = new PreferencesService();
  });

  describe('getPreferences', () => {
    it('should return default preferences for unknown user', () => {
      const prefs = service.getPreferences('user-1');
      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
    });

    it('should return a copy, not a reference', () => {
      service.updateEmailPreferences('user-1', { enabled: true });
      const a = service.getPreferences('user-1');
      const b = service.getPreferences('user-1');
      a.email.subscribedCategories.push('user:welcome');
      expect(b.email.subscribedCategories).not.toContain('user:welcome');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      const prefs = service.updateEmailPreferences('user-1', { enabled: false });
      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('immediate'); // unchanged
    });

    it('should change frequency', () => {
      const prefs = service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });
      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.enabled).toBe(true); // unchanged
    });

    it('should update subscribed categories', () => {
      const prefs = service.updateEmailPreferences('user-1', {
        subscribedCategories: ['order:confirmation'],
      });
      expect(prefs.email.subscribedCategories).toEqual(['order:confirmation']);
    });

    it('should merge partial updates', () => {
      service.updateEmailPreferences('user-1', { frequency: 'weekly-digest' });
      const prefs = service.updateEmailPreferences('user-1', { enabled: false });
      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should set updatedAt timestamp', () => {
      const before = new Date();
      const prefs = service.updateEmailPreferences('user-1', { enabled: true });
      expect(prefs.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true with default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });

    it('should return false for unsubscribed category', () => {
      service.updateEmailPreferences('user-1', {
        subscribedCategories: ['user:welcome'],
      });
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'user:welcome')).toBe(true);
    });

    it('should return false when email disabled even if category subscribed', () => {
      service.updateEmailPreferences('user-1', {
        enabled: false,
        subscribedCategories: ALL_NOTIFICATION_TYPES,
      });
      expect(service.shouldSendEmail('user-1', 'order:confirmation')).toBe(false);
    });
  });

  describe('getEmailFrequency', () => {
    it('should return immediate by default', () => {
      expect(service.getEmailFrequency('user-1')).toBe('immediate');
    });

    it('should return updated frequency', () => {
      service.updateEmailPreferences('user-1', { frequency: 'daily-digest' });
      expect(service.getEmailFrequency('user-1')).toBe('daily-digest');
    });
  });

  describe('deletePreferences', () => {
    it('should return false for non-existent preferences', () => {
      expect(service.deletePreferences('user-1')).toBe(false);
    });

    it('should delete and revert to defaults', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      expect(service.deletePreferences('user-1')).toBe(true);
      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
    });
  });

  describe('clearAll', () => {
    it('should remove all stored preferences', () => {
      service.updateEmailPreferences('user-1', { enabled: false });
      service.updateEmailPreferences('user-2', { frequency: 'daily-digest' });
      service.clearAll();
      expect(service.getPreferences('user-1').email.enabled).toBe(true);
      expect(service.getPreferences('user-2').email.frequency).toBe('immediate');
    });
  });
});

describe('createDefaultPreferences', () => {
  it('should create defaults with all categories subscribed', () => {
    const prefs = createDefaultPreferences('user-99');
    expect(prefs.userId).toBe('user-99');
    expect(prefs.email.enabled).toBe(true);
    expect(prefs.email.frequency).toBe('immediate');
    expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_TYPES);
    expect(prefs.updatedAt).toBeInstanceOf(Date);
  });
});

describe('NotificationService + PreferencesService integration', () => {
  let eventBus: EventBus;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    preferencesService = new PreferencesService();
    notificationService = new NotificationService(eventBus, preferencesService);
    resetNotificationIdCounter();
  });

  const makeOrderEvent = (): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  const makeUserEvent = (): UserCreatedEvent => ({
    type: 'user:created',
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  it('should send notification with default preferences', async () => {
    await eventBus.emit(makeOrderEvent());
    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.updateEmailPreferences('user-1', { enabled: false });
    await eventBus.emit(makeOrderEvent());
    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notification for unsubscribed category', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['user:welcome'],
    });
    await eventBus.emit(makeOrderEvent());
    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should send welcome but not order when only welcome subscribed', async () => {
    preferencesService.updateEmailPreferences('user-1', {
      subscribedCategories: ['user:welcome'],
    });
    await eventBus.emit(makeOrderEvent());
    await eventBus.emit(makeUserEvent());
    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotifications()[0]?.type).toBe('user:welcome');
  });

  it('should work without preferences service (backward compatible)', async () => {
    const service = new NotificationService(eventBus);
    // Use a different eventBus to avoid double-handling
    const bus2 = new EventBus();
    const svc2 = new NotificationService(bus2);
    await bus2.emit(makeOrderEvent());
    expect(svc2.getNotificationCount()).toBe(1);
  });
});

